/* ── Mobile responsive (overrides only) ── */
@media (max-width: 640px) {
    .editor-parent-container {
        z-index: 132;
    }
    .editor-container {
        width: 95%;
        height: 95%;
        padding: 0.75rem;
        border-radius: 12px;
    }
    /* Mobile toolbar: wrap into rows so all buttons are visible */
    .toolbar {
        flex-wrap: wrap;
        gap: 2px;
    }
    .toolbar-bttns,
    .is-active {
        padding: 0.55rem;
        min-width: 36px;
        min-height: 36px;
    }
    .toolbar-bttns svg,
    .is-active svg {
        width: 18px;
        height: 18px;
    }
    .toolbar-divider {
        margin: 0 4px;
        height: 16px;
    }
    .content-title-input {
        font-size: 1.35rem;
    }
    .editor-save-bttn {
        padding: 0.35rem 0.9rem;
        font-size: 0.85rem;

